<template><div class="detail-page"><div class="detail-header"><a-space><a-button @click="$router.back()"><arrow-left-outlined /></a-button><span class="page-title">商品详情</span></a-space></div><div class="detail-section"><a-descriptions title="信息" :column="2"><a-descriptions-item label="名称">{{pr?.name}}</a-descriptions-item><a-descriptions-item label="商家">{{pr?.merchantName}}</a-descriptions-item><a-descriptions-item label="类目">{{pr?.categoryName}}</a-descriptions-item><a-descriptions-item label="最低价">{{formatMoney(pr?.minPrice||0)}}</a-descriptions-item><a-descriptions-item label="总库存">{{pr?.totalStock}}</a-descriptions-item><a-descriptions-item label="销量">{{pr?.totalSales}}</a-descriptions-item></a-descriptions></div><div class="detail-section" v-if="pr?.skus?.length"><div class="section-title">SKU 列表</div><a-table :columns="skuCols" :data-source="pr?.skus" row-key="id" size="small" :pagination="false"/></div></div></template>
<script setup lang="ts">import {ref,onMounted} from 'vue';import {useRoute} from 'vue-router';import {ArrowLeftOutlined} from '@ant-design/icons-vue';import {shopApi} from '@/api/shop';import {formatMoney} from '@/utils/format'
const route=useRoute();const pr=ref<any>(null)
const skuCols=[{title:'规格',dataIndex:'name'},{title:'价格',dataIndex:'price'},{title:'库存',dataIndex:'stock'},{title:'预警',dataIndex:'alertStock'},{title:'销量',dataIndex:'sales'}]
onMounted(async()=>{const id=Number(route.params.id);const r=await shopApi.getProductDetail(id);pr.value=r.data.data});
</script>
